      CPU_STRICT: "Usa colocación estricta de CPU con CPU_RANGE.",
      POLL: "Nivel de sondeo mientras se espera trabajo, 0-100.",
      ROPE_SCALING: "Método de escalado RoPE: none, linear o yarn. Vacío usa el modelo/predeterminado.",
      ROPE_SCALE: "Factor de escalado de contexto RoPE. Vacío usa el modelo/predeterminado.",
      ROPE_FREQ_BASE: "Anulación de la frecuencia base RoPE. Vacío usa el modelo/predeterminado.",
